function solve(n: number): string {
    const n2 = n * n;
    const n3 = n * n * n;

    // Convert n2 to hexadecimal
    const hexPart = n2.toString(16).toUpperCase();

    // Convert n3 to base36
    let base36Part = '';
    let num = n3;
    while (num > 0) {
        const remainder = num % 36;
        let char;
        if (remainder < 10) {
            char = remainder.toString();
        } else {
            char = String.fromCharCode(65 + remainder - 10);
        }
        base36Part = char + base36Part;
        num = Math.floor(num / 36);
    }

    return hexPart + base36Part;
}

